mapper.update:

	UPDATE MST.TB_LVL_BAS M
    SET M.NMAX_SEQ=T.NMAX_SEQ, M.DMODIFY_DT=SYSDATE, M.SMODIFY_ID = #{smodifyId, jdbcType=VARCHAR}
    FROM ( 
		SELECT SSVC_LINE_TYPE_CD, SSVC_GROUP_CD, SSVC_OBJ_CD, MAX(NLVL_MST_SEQ) AS NMAX_SEQ
		FROM MST.TB_LVL_MST 
		GROUP BY SSVC_LINE_TYPE_CD, SSVC_GROUP_CD, SSVC_OBJ_CD
	) T
	WHERE M.SSVC_LINE_TYPE_CD = T.SSVC_LINE_TYPE_CD AND M.SSVC_GROUP_CD = T.SSVC_GROUP_CD AND M.SSVC_OBJ_CD = T.SSVC_OBJ_CD
	AND M.NMAX_SEQ != T.NMAX_SEQ
	AND M.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
	AND M.SSVC_GROUP_CD = #{ssvcGroupCd, jdbcType=CHAR}
	AND M.SSVC_OBJ_CD = #{ssvcObjCd, jdbcType=CHAR}

