SELECT 
	   , A.RNUM  FROM (
	SELECT 
	   , ROWNUM RNUM FROM (
		SELECT



		FROM MST.TB_LVL_BAS A



		AND D.SLVL_NM ILIKE '%'  ||  #{ssvcObjNm, jdbcType=VARCHAR} ||  '%'	



		ORDER BY A.NLVL_BAS_SEQ ASC

	) A WHERE ROWNUM <= #{lastIndex}
)A WHERE RNUM >= #{firstIndex}

SELECT '' AS SSVC_GROUP_CD , '전체' AS SSVC_GROUP_NM UNION ALL SELECT SLVL_CD AS SSVC_GROUP_CD , SLVL_NM AS SSVC_GROUP_NM FROM MST.TB_LVL_CD WHERE SLVL_CD = '000000' UNION ALL SELECT DISTINCT A.SSVC_GROUP_CD , B.SLVL_NM AS SSVC_GROUP_NM FROM MST.TB_LVL_BAS A ,MST.TB_LVL_CD B WHERE A.SSVC_GROUP_CD = B.SLVL_CD AND A.SLVL_BAS_LEVEL_CD = 'LL0002'
AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
ORDER BY SSVC_GROUP_CD ASC

SELECT '' AS SSVC_OBJ_CD , '전체' AS SSVC_OBJ_NM UNION ALL SELECT SLVL_CD AS SSVC_GROUP_CD , SLVL_NM AS SSVC_GROUP_NM FROM MST.TB_LVL_CD WHERE SLVL_CD = '000000' UNION ALL SELECT DISTINCT A.SSVC_OBJ_CD , B.SLVL_NM AS SSVC_OBJ_NM FROM MST.TB_LVL_BAS A ,MST.TB_LVL_CD B WHERE A.SSVC_OBJ_CD = B.SLVL_CD AND A.SLVL_BAS_LEVEL_CD = 'LL0003'
AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
AND A.SSVC_GROUP_CD = #{ssvcGroupCd, jdbcType=CHAR}
ORDER BY SSVC_OBJ_CD ASC

SELECT
	count(1) totalCount
FROM MST.TB_LVL_BAS A
WHERE 1 = 1	
AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
AND A.SSVC_GROUP_CD = #{ssvcGroupCd, jdbcType=CHAR}
AND A.SSVC_OBJ_CD = #{ssvcObjCd, jdbcType=CHAR}
